let v = UIView()
v.frame = CGRect(x: 20, y: 100, width: 120, height: 60)
// frame.origin = (20,100), bounds.origin = (0,0), bounds.size = (120,60)

// Subview is positioned in v's coordinate system
let inner = UIView(frame: CGRect(x: 10, y: 10, width: 20, height: 20))
v.addSubview(inner) // inner.frame.origin = (10,10) inside v

// Rotation invalidates frame — use bounds + transform
v.transform = CGAffineTransform(rotationAngle: .pi / 4)
print(v.frame)   // bounding box of rotated view — not the view's own size
print(v.bounds)  // unchanged

// UIScrollView-style scrolling — adjust contentOffset (which sets bounds.origin)
let scroll = UIScrollView()
scroll.contentOffset = CGPoint(x: 0, y: 100)
// equivalent to scroll.bounds.origin.y = 100

// center = (frame.origin + frame.size / 2)
v.center = CGPoint(x: 200, y: 300) // moves the frame, bounds untouched

