// Modern diffable data source for UICollectionView
class FeedVC: UIViewController {
  enum Section { case main }
  struct Item: Hashable { let id: UUID; let title: String }

  var collectionView: UICollectionView!
  var dataSource: UICollectionViewDiffableDataSource<Section, Item>!

  override func viewDidLoad() {
    super.viewDidLoad()

    let layout = UICollectionViewCompositionalLayout.list(using: .init(appearance: .insetGrouped))
    collectionView = UICollectionView(frame: view.bounds, collectionViewLayout: layout)
    view.addSubview(collectionView)

    let cellRegistration = UICollectionView.CellRegistration<UICollectionViewListCell, Item> { cell, _, item in
      var content = cell.defaultContentConfiguration()
      content.text = item.title
      cell.contentConfiguration = content
    }

    dataSource = .init(collectionView: collectionView) { cv, indexPath, item in
      cv.dequeueConfiguredReusableCell(using: cellRegistration, for: indexPath, item: item)
    }

    apply(items: load())
  }

  func apply(items: [Item]) {
    var snap = NSDiffableDataSourceSnapshot<Section, Item>()
    snap.appendSections([.main])
    snap.appendItems(items, toSection: .main)
    dataSource.apply(snap, animatingDifferences: true)
  }
  func load() -> [Item] { [] }
}

